syntax = "proto3";

package envoy.extensions.filters.http.custom_header_injection.v3;

import "udpa/annotations/migrate.proto";
import "udpa/annotations/status.proto";
import "udpa/annotations/versioning.proto";
import "validate/validate.proto";

option java_package = "io.envoyproxy.envoy.extensions.filters.http.custom_header_injection.v3";
option java_outer_classname = "CustomHeaderInjectionProto";
option java_multiple_files = true;
option go_package = "github.com/envoyproxy/go-control-plane/envoy/extensions/filters/http/custom_header_injection/v3;custom_header_injectionv3";
option (udpa.annotations.file_status).package_version_status = ACTIVE;

// [#protodoc-title: Custom Header Injection Filter]
//
// The configuration for injecting custom headers into requests and/or responses
// based on route metadata.
//
// Custom Header Injection :ref:`configuration overview <config_http_filters_custom_header_injection>`.
// [#extension: envoy.filters.http.custom_header_injection]

message Config {
  option (udpa.annotations.versioning).previous_message_type =
      "envoy.config.filter.http.custom_header_injection.v1.Config";

  // Header injection rule
  // [#next-free-field: 4]
  message HeaderValue {
    option (udpa.annotations.versioning).previous_message_type =
        "envoy.config.filter.http.custom_header_injection.v1.Config.HeaderValue";

    // The header key to inject
    string header_name = 1 [(validate.rules).string = {
      well_known_regex: HTTP_HEADER_NAME
      strict: false
    }];

    // The header value to inject
    string header_value = 2;
  }

  // Request headers to inject
  repeated HeaderValue request_headers_to_inject = 1;

  // Response headers to inject
  repeated HeaderValue response_headers_to_inject = 2;
}

#pragma once

#include <vector>

#include "envoy/extensions/filters/http/custom_header_injection/v3/custom_header_injection.pb.h"
#include "envoy/server/filter_config.h"

#include "source/common/common/logger.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

using ProtoConfig = envoy::extensions::filters::http::custom_header_injection::v3::Config;
using ProtoHeaderValue = envoy::extensions::filters::http::custom_header_injection::v3::Config::HeaderValue;

/**
 * Configuration for the Custom Header Injection filter.
 * Encapsulates header injection rules for requests and responses.
 */
class Config : public ::Envoy::Router::RouteSpecificFilterConfig,
               public Logger::Loggable<Logger::Id::config> {
public:
  Config(const ProtoConfig& proto_config);

  // Getters for request and response header injection rules
  const std::vector<ProtoHeaderValue>& requestHeadersToInject() const {
    return request_headers_to_inject_;
  }
  const std::vector<ProtoHeaderValue>& responseHeadersToInject() const {
    return response_headers_to_inject_;
  }

private:
  std::vector<ProtoHeaderValue> request_headers_to_inject_;
  std::vector<ProtoHeaderValue> response_headers_to_inject_;
};

using ConfigSharedPtr = std::shared_ptr<Config>;

/**
 * Custom Header Injection filter that injects configurable headers into
 * requests and/or responses based on filter configuration.
 */
class CustomHeaderInjectionFilter : public Http::StreamFilter,
                                    public Logger::Loggable<Logger::Id::filter> {
public:
  CustomHeaderInjectionFilter(const ConfigSharedPtr config);
  ~CustomHeaderInjectionFilter() override;

  // Http::StreamFilterBase
  void onDestroy() override {}

  // StreamDecoderFilter
  Http::FilterHeadersStatus decodeHeaders(Http::RequestHeaderMap& headers, bool) override;
  Http::FilterDataStatus decodeData(Buffer::Instance&, bool) override {
    return Http::FilterDataStatus::Continue;
  }
  Http::FilterTrailersStatus decodeTrailers(Http::RequestTrailerMap&) override {
    return Http::FilterTrailersStatus::Continue;
  }
  void setDecoderFilterCallbacks(Http::StreamDecoderFilterCallbacks& callbacks) override;

  // StreamEncoderFilter
  Http::Filter1xxHeadersStatus encode1xxHeaders(Http::ResponseHeaderMap&) override {
    return Http::Filter1xxHeadersStatus::Continue;
  }
  Http::FilterHeadersStatus encodeHeaders(Http::ResponseHeaderMap& headers, bool) override;
  Http::FilterDataStatus encodeData(Buffer::Instance&, bool) override {
    return Http::FilterDataStatus::Continue;
  }
  Http::FilterTrailersStatus encodeTrailers(Http::ResponseTrailerMap&) override {
    return Http::FilterTrailersStatus::Continue;
  }
  Http::FilterMetadataStatus encodeMetadata(Http::MetadataMap&) override {
    return Http::FilterMetadataStatus::Continue;
  }
  void setEncoderFilterCallbacks(Http::StreamEncoderFilterCallbacks& callbacks) override;

private:
  const ConfigSharedPtr config_;
  mutable const Config* effective_config_{nullptr};
  Http::StreamDecoderFilterCallbacks* decoder_callbacks_{};
  Http::StreamEncoderFilterCallbacks* encoder_callbacks_{};

  // Helper method to inject headers into a header map
  void injectHeaders(Http::HeaderMap& headers, const std::vector<ProtoHeaderValue>& headers_to_inject);

  // Get the effective config (route-specific or global)
  const Config* getConfig() const;
};

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

#include "source/extensions/filters/http/custom_header_injection/filter.h"

#include "envoy/extensions/filters/http/custom_header_injection/v3/custom_header_injection.pb.h"

#include "source/common/http/utility.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

Config::Config(const ProtoConfig& proto_config) {
  for (const auto& header : proto_config.request_headers_to_inject()) {
    request_headers_to_inject_.push_back(header);
  }
  for (const auto& header : proto_config.response_headers_to_inject()) {
    response_headers_to_inject_.push_back(header);
  }
}

CustomHeaderInjectionFilter::CustomHeaderInjectionFilter(const ConfigSharedPtr config)
    : config_(config) {}

CustomHeaderInjectionFilter::~CustomHeaderInjectionFilter() = default;

Http::FilterHeadersStatus
CustomHeaderInjectionFilter::decodeHeaders(Http::RequestHeaderMap& headers, bool) {
  const auto* config = getConfig();
  injectHeaders(headers, config->requestHeadersToInject());
  return Http::FilterHeadersStatus::Continue;
}

void CustomHeaderInjectionFilter::setDecoderFilterCallbacks(
    Http::StreamDecoderFilterCallbacks& callbacks) {
  decoder_callbacks_ = &callbacks;
}

Http::FilterHeadersStatus
CustomHeaderInjectionFilter::encodeHeaders(Http::ResponseHeaderMap& headers, bool) {
  const auto* config = getConfig();
  injectHeaders(headers, config->responseHeadersToInject());
  return Http::FilterHeadersStatus::Continue;
}

void CustomHeaderInjectionFilter::setEncoderFilterCallbacks(
    Http::StreamEncoderFilterCallbacks& callbacks) {
  encoder_callbacks_ = &callbacks;
}

void CustomHeaderInjectionFilter::injectHeaders(
    Http::HeaderMap& headers, const std::vector<ProtoHeaderValue>& headers_to_inject) {
  for (const auto& header_value : headers_to_inject) {
    headers.setCopy(Http::LowerCaseString(header_value.header_name()), header_value.header_value());
  }
}

const Config* CustomHeaderInjectionFilter::getConfig() const {
  // Cached config pointer.
  if (effective_config_) {
    return effective_config_;
  }

  effective_config_ =
      Http::Utility::resolveMostSpecificPerFilterConfig<Config>(decoder_callbacks_);
  if (effective_config_) {
    return effective_config_;
  }

  effective_config_ = config_.get();
  return effective_config_;
}

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

