#include "test/mocks/http/mocks.h"
#include "test/mocks/stream_info/mocks.h"
#include "test/test_common/utility.h"

#include "gmock/gmock.h"
#include "gtest/gtest.h"

using testing::NiceMock;

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {
namespace {

class CustomHeaderInjectionFilterTest : public testing::Test {
public:
  CustomHeaderInjectionFilterTest() = default;

  void SetUp() override {
    const envoy::extensions::filters::http::custom_header_injection::v3::Config config =
        makeConfig("");
    auto config_ptr = std::make_shared<Config>(config);

    filter_ = std::make_unique<CustomHeaderInjectionFilter>(config_ptr);
    filter_->setDecoderFilterCallbacks(decoder_callbacks_);
    filter_->setEncoderFilterCallbacks(encoder_callbacks_);
  }

  void TearDown() override { filter_.reset(); }

  envoy::extensions::filters::http::custom_header_injection::v3::Config
  makeConfig(const std::string& yaml_config) {
    envoy::extensions::filters::http::custom_header_injection::v3::Config proto;
    if (!yaml_config.empty()) {
      TestUtility::loadFromYamlAndValidate(yaml_config, proto);
    }
    return proto;
  }

  NiceMock<Http::MockStreamDecoderFilterCallbacks> decoder_callbacks_;
  NiceMock<Http::MockStreamEncoderFilterCallbacks> encoder_callbacks_;
  std::unique_ptr<CustomHeaderInjectionFilter> filter_;
};

TEST_F(CustomHeaderInjectionFilterTest, DecodeHeadersInjectRequestHeaders) {
  std::string yaml_config =
      R"EOF(
request_headers_to_inject:
  - header_name: "x-custom-request"
    header_value: "request-value"
)EOF";

  auto config = makeConfig(yaml_config);
  auto config_ptr = std::make_shared<Config>(config);
  filter_ = std::make_unique<CustomHeaderInjectionFilter>(config_ptr);
  filter_->setDecoderFilterCallbacks(decoder_callbacks_);
  filter_->setEncoderFilterCallbacks(encoder_callbacks_);

  Http::TestRequestHeaderMapImpl request_headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->decodeHeaders(request_headers, false));

  EXPECT_EQ("request-value", request_headers.get_("x-custom-request"));
}

TEST_F(CustomHeaderInjectionFilterTest, EncodeHeadersInjectResponseHeaders) {
  std::string yaml_config =
      R"EOF(
response_headers_to_inject:
  - header_name: "x-custom-response"
    header_value: "response-value"
)EOF";

  auto config = makeConfig(yaml_config);
  auto config_ptr = std::make_shared<Config>(config);
  filter_ = std::make_unique<CustomHeaderInjectionFilter>(config_ptr);
  filter_->setDecoderFilterCallbacks(decoder_callbacks_);
  filter_->setEncoderFilterCallbacks(encoder_callbacks_);

  Http::TestResponseHeaderMapImpl response_headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->encodeHeaders(response_headers, false));

  EXPECT_EQ("response-value", response_headers.get_("x-custom-response"));
}

TEST_F(CustomHeaderInjectionFilterTest, DecodeHeadersNoInjectionWithoutConfig) {
  Http::TestRequestHeaderMapImpl request_headers;
  request_headers.addCopy("existing-header", "existing-value");

  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->decodeHeaders(request_headers, false));

  EXPECT_EQ("existing-value", request_headers.get_("existing-header"));
}

TEST_F(CustomHeaderInjectionFilterTest, MultipleHeaderInjection) {
  std::string yaml_config =
      R"EOF(
request_headers_to_inject:
  - header_name: "x-custom-1"
    header_value: "value-1"
  - header_name: "x-custom-2"
    header_value: "value-2"
)EOF";

  auto config = makeConfig(yaml_config);
  auto config_ptr = std::make_shared<Config>(config);
  filter_ = std::make_unique<CustomHeaderInjectionFilter>(config_ptr);
  filter_->setDecoderFilterCallbacks(decoder_callbacks_);
  filter_->setEncoderFilterCallbacks(encoder_callbacks_);

  Http::TestRequestHeaderMapImpl request_headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->decodeHeaders(request_headers, false));

  EXPECT_EQ("value-1", request_headers.get_("x-custom-1"));
  EXPECT_EQ("value-2", request_headers.get_("x-custom-2"));
}

} // namespace
} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

