    94→Config::Config(const envoy::extensions::filters::http::header_to_metadata::v3::Config config,
    95→               Regex::Engine& regex_engine, const bool per_route) {
    96→  request_set_ = Config::configToVector(config.request_rules(), request_rules_, regex_engine);
    97→  response_set_ = Config::configToVector(config.response_rules(), response_rules_, regex_engine);
    98→
    99→  // Note: empty configs are fine for the global config, which would be the case for enabling
   100→  //       the filter globally without rules and then applying them at the virtual host or
   101→  //       route level. At the virtual or route level, it makes no sense to have an empty
   102→  //       config so we throw an error.
   103→  if (per_route && !response_set_ && !request_set_) {
   104→    throw EnvoyException("header_to_metadata_filter: Per filter configs must at least specify "
   105→                         "either request or response rules");
   106→  }
   107→}
